1	import {
2	  Transaction,
3	  CategoryGroup,
4	  DuplicateGroup,
5	  RunningBalanceEntry,
6	  SpenderSummary,
7	  PipelineResult,
8	} from "./types.js";
9	
10	/**
11	 * Groups transactions by category and calculates totals.
12	 *
13	 * KNOWN PERFORMANCE ISSUE: Uses array.find and array.filter instead of a Map,
14	 * and recalculates totals with reduce on every insert.
15	 */
16	export function groupByCategory(transactions: Transaction[]): CategoryGroup[] {
17	  const groups: CategoryGroup[] = [];
18	
19	  for (const transaction of transactions) {
20	    // SLOW: Linear scan through groups for every transaction
21	    const existingGroup = groups.find(
22	      (g) => g.category === transaction.category
23	    );
24	
25	    if (existingGroup) {
26	      existingGroup.transactions.push(transaction);
27	      // SLOW: Recalculate total using reduce instead of just adding the amount
28	      existingGroup.total = existingGroup.transactions.reduce(
29	        (sum, t) => sum + t.amount,
30	        0
31	      );
32	    } else {
33	      groups.push({
34	        category: transaction.category,
35	        transactions: [transaction],
36	        total: transaction.amount,
37	      });
38	    }
39	  }
40	
41	  return groups;
42	}
43	
44	/**
45	 * Finds duplicate transactions (same userId + amount + date).
46	 *
47	 * KNOWN PERFORMANCE ISSUE: Compares every pair of transactions O(n^2).
48	 */
49	export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
50	  const duplicateGroups: DuplicateGroup[] = [];
51	
52	  // SLOW: Compare every transaction against every other transaction
53	  for (let i = 0; i < transactions.length; i++) {
54	    for (let j = i + 1; j < transactions.length; j++) {
55	      const a = transactions[i];
56	      const b = transactions[j];
57	
58	      if (
59	        a.userId === b.userId &&
60	        a.amount === b.amount &&
61	        a.date === b.date
62	      ) {
63	        const key = `${a.userId}|${a.amount}|${a.date}`;
64	
65	        // SLOW: Linear scan to find if this duplicate group already exists
66	        let found = false;
67	        for (const group of duplicateGroups) {
68	          if (group.key === key) {
69	            let aExists = false;
70	            let bExists = false;
71	            for (const t of group.transactions) {
72	              if (t.id === a.id) aExists = true;
73	              if (t.id === b.id) bExists = true;
74	            }
75	            if (!aExists) group.transactions.push(a);
76	            if (!bExists) group.transactions.push(b);
77	            found = true;
78	            break;
79	          }
80	        }
81	
82	        if (!found) {
83	          duplicateGroups.push({
84	            key,
85	            transactions: [a, b],
86	          });
87	        }
88	      }
89	    }
90	  }
91	
92	  return duplicateGroups;
93	}
94	
95	/**
96	 * Calculates running balance for a specific user, sorted by date.
97	 *
98	 * KNOWN PERFORMANCE ISSUE: For each user transaction, rescans the entire
99	 * transactions array to re-filter and re-sort user transactions, then
100	 * recalculates the running balance from scratch.
101	 */
102	export function calculateRunningBalance(
103	  transactions: Transaction[],
104	  userId: string
105	): RunningBalanceEntry[] {
106	  // First pass: count how many transactions this user has
107	  let userCount = 0;
108	  for (const t of transactions) {
109	    if (t.userId === userId) {
110	      userCount++;
111	    }
112	  }
113	
114	  const entries: RunningBalanceEntry[] = [];
115	
116	  // SLOW: For each user transaction position, rescan the ENTIRE transactions
117	  // array to filter, sort, and compute balance from scratch
118	  for (let position = 0; position < userCount; position++) {
119	    // Rescan all transactions to find this user's transactions
120	    const userTransactions: Transaction[] = [];
121	    for (const t of transactions) {
122	      if (t.userId === userId) {
123	        userTransactions.push(t);
124	      }
125	    }
126	
127	    // Re-sort every iteration
128	    userTransactions.sort((a, b) => a.date.localeCompare(b.date));
129	
130	    // Recalculate balance up to this position
131	    let balance = 0;
132	    for (let j = 0; j <= position; j++) {
133	      balance += userTransactions[j].amount;
134	    }
135	    balance = Math.round(balance * 100) / 100;
136	
137	    entries.push({
138	      transactionId: userTransactions[position].id,
139	      amount: userTransactions[position].amount,
140	      balance,
141	      date: userTransactions[position].date,
142	    });
143	  }
144	
145	  return entries;
146	}
147	
148	/**
149	 * Returns the top N spenders.
150	 *
151	 * KNOWN PERFORMANCE ISSUE: For each unique user, rescans the entire
152	 * transactions array to calculate their total, then uses bubble sort.
153	 */
154	export function topSpenders(
155	  transactions: Transaction[],
156	  n: number
157	): SpenderSummary[] {
158	  // SLOW: Collect unique user IDs by scanning array with includes check
159	  const userIds: string[] = [];
160	  for (const t of transactions) {
161	    if (!userIds.includes(t.userId)) {
162	      userIds.push(t.userId);
163	    }
164	  }
165	
166	  // SLOW: For each user, scan ALL transactions to calculate their total
167	  const summaries: SpenderSummary[] = [];
168	  for (const userId of userIds) {
169	    let total = 0;
170	    let count = 0;
171	    for (const t of transactions) {
172	      if (t.userId === userId) {
173	        total += t.amount;
174	        count++;
175	      }
176	    }
177	    summaries.push({
178	      userId,
179	      totalSpent: Math.round(total * 100) / 100,
180	      transactionCount: count,
181	    });
182	  }
183	
184	  // SLOW: Bubble sort to order by totalSpent descending
185	  for (let i = 0; i < summaries.length; i++) {
186	    for (let j = 0; j < summaries.length - i - 1; j++) {
187	      if (summaries[j].totalSpent < summaries[j + 1].totalSpent) {
188	        const temp = summaries[j];
189	        summaries[j] = summaries[j + 1];
190	        summaries[j + 1] = temp;
191	      }
192	    }
193	  }
194	
195	  return summaries.slice(0, n);
196	}
