116	  // SLOW: For each user transaction position, rescan the ENTIRE transactions
117	  // array to filter, sort, and compute balance from scratch
118	  for (let position = 0; position < userCount; position++) {
119	    // Rescan all transactions to find this user's transactions
120	    const userTransactions: Transaction[] = [];
121	    for (const t of transactions) {
122	      if (t.userId === userId) {
123	        userTransactions.push(t);
124	      }
125	    }
126	
127	    // Re-sort every iteration
128	    userTransactions.sort((a, b) => a.date.localeCompare(b.date));
129	
130	    // Recalculate balance up to this position
131	    let balance = 0;
132	    for (let j = 0; j <= position; j++) {
133	      balance += userTransactions[j].amount;
134	    }
135	    balance = Math.round(balance * 100) / 100;
136	
137	    entries.push({
138	      transactionId: userTransactions[position].id,
139	      amount: userTransactions[position].amount,
