```ts
export function groupByCategory(transactions: Transaction[]): CategoryGroup[] {
  const groups: CategoryGroup[] = [];
  for (const transaction of transactions) {
    const existingGroup = groups.find(g => g.category === transaction.category); // O(n) scan per txn
    if (existingGroup) {
      existingGroup.transactions.push(transaction);
      existingGroup.total = existingGroup.transactions.reduce((sum, t) => sum + t.amount, 0); // recalculates entire total
    } else {
      groups.push({ category: transaction.category, transactions: [transaction], total: transaction.amount });
    }
  }
